        }, 0);
      } else {
        const error = await res.json();
        alert(error.error || "Failed to upload image");
      }
    } catch (err) {
      console.error("Failed to upload image:", err);
      alert("Failed to upload image");
    } finally {
      setUploadingImage(false);
    }
  };

  const insertMarkdown = (before: string, after = "", textarea: HTMLTextAreaElement | null) => {
    if (!textarea) return;
    
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = textarea.value;
    const selectedText = text.substring(start, end);
    const newText = text.substring(0, start) + before + selectedText + after + text.substring(end);
    
    setNewThread({ ...newThread, content: newText });
    
    setTimeout(() => {
      textarea.focus();
      textarea.setSelectionRange(start + before.length, end + before.length);
    }, 0);
  };

  const [searchTrigger, setSearchTrigger] = useState(0);

  useEffect(() => {
    if (!category) return;

    const loadThreads = async () => {
      setLoading(true);
      const searchParam = searchQuery ? `&search=${encodeURIComponent(searchQuery)}` : "";

      try {
        const res = await apiFetch(`/api/community/threads?category=${category}&page=${page}&limit=20${searchParam}`);
        const data = await res.json().catch(() => null);
        const serverThreads = Array.isArray(data?.threads) ? data.threads : [];

        if (serverThreads.length > 0) {
          setThreads(serverThreads);
          setHasMore(data.pagination?.hasMore || false);
          setTotalPages(Math.ceil((data.pagination?.total || 0) / (data.pagination?.limit || 20)));
          setUsingMockData(false);
          return;
        }

        const mockThreads = getMockCommunityThreadsForCategory(category, searchQuery);
        setThreads(mockThreads);
        setHasMore(false);
        setTotalPages(mockThreads.length > 0 ? 1 : 0);
        setUsingMockData(true);
      } catch (err) {
        console.error("Failed to load threads:", err);
        const mockThreads = getMockCommunityThreadsForCategory(category, searchQuery);
        setThreads(mockThreads);
        setHasMore(false);
        setTotalPages(mockThreads.length > 0 ? 1 : 0);
        setUsingMockData(true);
      } finally {
        setLoading(false);
      }
    };

    void loadThreads();
  }, [category, page, searchTrigger]);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    setPage(1);
    setSearchTrigger(prev => prev + 1); // Trigger search
  };

  const handleCreateThread = async () => {
    if (!newThread.title.trim() || !newThread.content.trim() || !category) return;

    setSubmitting(true);
    try {
      const res = await fetch("/api/community/threads", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          category_slug: category,
          title: newThread.title.trim(),
          content: newThread.content.trim(),
        }),
      });

      if (res.ok) {
        const data = await res.json();
        await sendMentionNotifications({
          recipientIds: mentionedUserIds.current,
          referenceType: "community_thread",
          referenceId: data.id,
          content: `Mentioned you in the thread "${newThread.title.trim()}"`,
        }).catch((error) => {
          console.error("Failed to send thread mention notifications:", error);
        });

        setThreads((current) => [data, ...current]);
        setNewThread({ title: "", content: "" });
        setShowNewThreadForm(false);
        mentionedUserIds.current = [];
      } else {
        alert("Failed to create thread");
      }
    } catch (err) {
      console.error("Failed to create thread:", err);
      alert("Failed to create thread");
    } finally {
      setSubmitting(false);
    }
  };

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 60) return `${diffMins}m ago`;
    if (diffHours < 24) return `${diffHours}h ago`;
    if (diffDays < 7) return `${diffDays}d ago`;
    return date.toLocaleDateString();
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-background pt-24 pb-16">
        <div className="max-w-6xl mx-auto px-4">
          <div className="animate-pulse space-y-4">
            <div className="h-12 bg-card rounded-lg"></div>
            <div className="h-24 bg-card rounded-lg"></div>
            <div className="h-24 bg-card rounded-lg"></div>
          </div>
        </div>
      </div>
    );
  }

  const mockCategoryName =
    getMockCommunityCategories().find((item) => item.slug === category)?.name || category;
  const categoryName = threads[0]?.category_name || mockCategoryName;

  return (
    <div className="min-h-screen bg-background pt-24 pb-16">
      <div className="max-w-6xl mx-auto px-4">
        {/* Header */}
        <div className="mb-8">
          <Link
            to="/community"
            className="inline-flex items-center gap-2 text-muted-foreground hover:text-foreground mb-4"
          >
            <ArrowLeft className="w-4 h-4" />
            Back to categories
          </Link>

          <div className="flex items-center justify-between mb-6">
            <h1 className="text-3xl md:text-4xl font-bold bg-gradient-to-r from-accent to-primary bg-clip-text text-transparent">
              {categoryName}
            </h1>
            {usingMockData ? (
              <div className="rounded-full border border-accent/30 bg-accent/5 px-4 py-2 text-xs font-semibold uppercase tracking-wider text-accent">
                Sample data only
              </div>
            ) : user ? (
              <Button 
                className="gap-2"
                onClick={() => setShowNewThreadForm(true)}
              >
                <Plus className="w-4 h-4" />
                {t("community.create_thread", "Create Thread")}
              </Button>
            ) : (
              <Link to="/login">
                <Button variant="outline" className="gap-2">
                  <Plus className="w-4 h-4" />
                  {t("community.login_to_post", "Login to Post")}
                </Button>
              </Link>
            )}
          </div>

          {/* Search */}
          <form onSubmit={handleSearch} className="flex gap-2">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
              <Input
                type="text"
                placeholder={t("community.search_placeholder", "Search threads...")}
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10"
              />
            </div>
            {searchQuery && (
              <Button
                type="button"
                variant="outline"
                onClick={() => {
                  setSearchQuery("");
                  setPage(1);
                  setSearchTrigger(prev => prev + 1);
                }}
              >
                {t("community.clear", "Clear")}
              </Button>
            )}
          </form>
        </div>

        {/* New Thread Form */}
        {showNewThreadForm && (
          <div className="mb-6 bg-card border border-border rounded-xl p-6">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-xl font-bold">{t("community.create_thread", "Create Thread")}</h2>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => {
                  setShowNewThreadForm(false);
                  setShowPreview(false);
                }}
              >
                <X className="w-4 h-4" />
              </Button>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium mb-2">{t("community.thread_form.title_placeholder", "Thread title...")}</label>
                <Input
                  id="thread-title"
                  placeholder={t("community.thread_form.title_placeholder", "Thread title...")}
                  value={newThread.title}
                  onChange={(e) => setNewThread({ ...newThread, title: e.target.value })}
                  disabled={submitting}
                />
              </div>

              <div>
                <div className="flex items-center justify-between mb-2">
                  <label className="block text-sm font-medium">{t("community.thread_form.content_placeholder", "Write your post content here...")}</label>
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    onClick={() => setShowPreview(!showPreview)}
                  >
                    {showPreview ? t("community.thread_form.edit", "Edit") : t("community.thread_form.preview", "Preview")}
                  </Button>
                </div>

                {!showPreview ? (
                  <>
                    <div className="flex items-center gap-1 mb-2 pb-2 border-b border-border">
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        className="h-8 px-2"
                        onClick={() => insertMarkdown("**", "**", threadContentTextareaRef.current)}
                        title="Bold"
                      >
                        <Bold className="w-4 h-4" />
                      </Button>
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        className="h-8 px-2"
                        onClick={() => insertMarkdown("*", "*", threadContentTextareaRef.current)}
                        title="Italic"
                      >
                        <Italic className="w-4 h-4" />
                      </Button>
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        className="h-8 px-2"
                        onClick={() => insertMarkdown("`", "`", threadContentTextareaRef.current)}
                        title="Code"
                      >
                        <Code className="w-4 h-4" />
                      </Button>
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        className="h-8 px-2"
                        onClick={() => insertMarkdown("[", "](url)", threadContentTextareaRef.current)}
                        title="Link"
                      >
                        <LinkIcon className="w-4 h-4" />
                      </Button>
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        className="h-8 px-2"
                        onClick={() => insertMarkdown("- ", "", threadContentTextareaRef.current)}
                        title="Bullet List"
                      >
                        <List className="w-4 h-4" />
                      </Button>
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        className="h-8 px-2"
                        onClick={() => insertMarkdown("1. ", "", threadContentTextareaRef.current)}
                        title="Numbered List"
                      >
                        <ListOrdered className="w-4 h-4" />
                      </Button>
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        className="h-8 px-2"
                        onClick={() => imageInputRef.current?.click()}
                        disabled={uploadingImage}
                        title="Upload Image"
                      >
                        <Image className="w-4 h-4" />
                      </Button>
                      <input
                        ref={imageInputRef}
                        type="file"
                        accept="image/*"
                        className="hidden"
                        onChange={(e) => {
                          const file = e.target.files?.[0];
                          if (file) handleImageUpload(file);
                          e.target.value = "";
                        }}
                      />
                    </div>
                    <MentionInput
                      placeholder={t("community.thread_form.content_placeholder", "Write your post content here...")}
                      value={newThread.content}
                      onChange={(value) => setNewThread({ ...newThread, content: value })}
                      onMentionsChange={(ids) => {
                        mentionedUserIds.current = ids;
                      }}
                      textareaRef={threadContentTextareaRef}
                      disabled={submitting || uploadingImage}
                      rows={6}
                      className="font-mono text-sm"
                    />
                  </>
                ) : (
                  <div className="min-h-32 p-4 bg-background rounded-lg border border-border prose prose-invert prose-sm max-w-none">
                    {newThread.content ? (
                      <ReactMarkdown remarkPlugins={[remarkGfm]}>
                        {replaceMentionTokens(newThread.content)}
                      </ReactMarkdown>
                    ) : (
                      <p className="text-muted-foreground">Nothing to preview</p>
                    )}
                  </div>
                )}
              </div>

              <div className="flex gap-3">
                <Button
                  onClick={handleCreateThread}
                  disabled={!newThread.title.trim() || !newThread.content.trim() || submitting}
                >
                  {submitting ? t("community.thread_form.posting", "Posting...") : t("community.thread_form.post_thread", "Post Thread")}
                </Button>
                <Button
                  variant="outline"
                  onClick={() => {
                    setShowNewThreadForm(false);
                    setShowPreview(false);
                  }}
                  disabled={submitting}
                >
                  {t("community.thread_form.cancel", "Cancel")}
                </Button>
              </div>
            </div>
          </div>
        )}

        {/* Threads */}
        <div className="space-y-3">
          {threads.map((thread) => (
            <Link
              key={thread.id}
              to={`/community/thread/${thread.slug}`}
              className="block bg-card hover:bg-card/80 border border-border rounded-xl p-5 transition-all hover:scale-[1.01]"
            >
              <div className="flex items-start gap-4">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-2">
                    {thread.is_pinned && (
                      <Pin className="w-4 h-4 text-accent flex-shrink-0" />
                    )}
                    {thread.is_locked && (
                      <Lock className="w-4 h-4 text-muted-foreground flex-shrink-0" />
                    )}
                    <h2 className="font-semibold truncate">{thread.title}</h2>
                  </div>

                  <div className="flex items-center gap-4 text-sm text-muted-foreground">
                    <span>by {thread.author_name || "Community member"}</span>
                    <span>•</span>
                    <span>{formatDate(thread.created_at)}</span>
                  </div>
                </div>

                {/* Stats */}
                <div className="flex items-center gap-6 text-sm text-muted-foreground">
                  <div className="flex items-center gap-1">
                    <MessageSquare className="w-4 h-4" />
                    <span>{thread.post_count || 0}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <Eye className="w-4 h-4" />
                    <span>{thread.view_count || 0}</span>
                  </div>
                </div>
              </div>

              {/* Last activity */}
              {thread.last_post_at && (
                <div className="mt-3 pt-3 border-t border-border text-xs text-muted-foreground">
                  Last activity {formatDate(thread.last_post_at)}
                </div>
              )}
            </Link>
          ))}
        </div>

        {/* Empty state */}
        {threads.length === 0 && !loading && (
          <div className="text-center py-16">
            <MessageSquare className="w-16 h-16 mx-auto mb-4 text-muted-foreground opacity-50" />
            <p className="text-muted-foreground mb-4">No threads in this category yet.</p>
            {user && !usingMockData && (
              <Button 
                className="gap-2"
                onClick={() => setShowNewThreadForm(true)}
              >
                <Plus className="w-4 h-4" />
                Start the first discussion
              </Button>
            )}
          </div>
        )}

        {/* Pagination */}
        {totalPages > 1 && (
          <div className="flex items-center justify-center gap-2 mt-8">
            <Button
              variant="outline"
              onClick={() => setPage(page - 1)}
              disabled={page === 1}
            >
              Previous
            </Button>
            <span className="text-sm text-muted-foreground px-4">
              Page {page} of {totalPages}
            </span>
            <Button
              variant="outline"
              onClick={() => setPage(page + 1)}
              disabled={!hasMore}
            >
              Next
            </Button>
          </div>
        )}
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { Link, useSearchParams } from "react-router";
import { useTranslation } from "react-i18next";
import { AlertCircle, BookOpen, CheckCircle, Mail, MessageCircle, PhoneCall, Send, Sparkles } from "lucide-react";
import GlitchedText from "@/react-app/components/GlitchedText";
import SEO from "@/react-app/components/SEO";
import { EXTERNAL_LINKS } from "@/react-app/lib/site";

type FeedbackState = {
  type: "success" | "error";
  text: string;
};

async function parseResponse(response: Response) {
  return response.json().catch(() => null);
}

export default function Contact() {
  const { t } = useTranslation();
  const [searchParams] = useSearchParams();
  const intent = searchParams.get("intent");
  const tier = searchParams.get("tier");
  const industry = searchParams.get("industry");
  const phone = searchParams.get("phone");
  const source = searchParams.get("source") || "contact_page";
  const [formState, setFormState] = useState({
    name: "",
    email: "",
    phone: "",
    subject: "",
    message: "",
    smsConsent: false,
  });
  const [earlyAccessEmail, setEarlyAccessEmail] = useState("");
  const [earlyAccessInterest, setEarlyAccessInterest] = useState("");
  const [sending, setSending] = useState(false);
  const [earlyAccessSending, setEarlyAccessSending] = useState(false);
  const [formFeedback, setFormFeedback] = useState<FeedbackState | null>(null);
  const [earlyAccessFeedback, setEarlyAccessFeedback] = useState<FeedbackState | null>(null);

  const requestPresets = [
    {
      key: "start-project",
      label: "Start Project",
      subject: "Start a new project",
      message:
        "Project name:\nIndustry:\nMain goal:\nCurrent tools:\nTarget launch window:\n",
    },
    {
      key: "automation-build",
      label: "Automation Build",
      subject: "Request service automation build",
      message:
        "Business name:\nIndustry:\nMain workflow to automate:\nCurrent tools used:\nTop problem to solve first:\n",
    },
    {
      key: "general-support",
      label: "General",
      subject: "General inquiry",
      message: "",
    },
  ];

  const formatTierLabel = (value: string) => value.charAt(0).toUpperCase() + value.slice(1).toLowerCase();

  const fillTemplateLine = (template: string, label: string, value: string | null | undefined) => {
    if (!value) {
      return template;
    }

    const safeValue = value.trim();
    if (!safeValue) {
      return template;
    }

    const pattern = new RegExp(`^${label}:.*$`, "m");
    if (pattern.test(template)) {
      return template.replace(pattern, `${label}: ${safeValue}`);
    }

    return `${label}: ${safeValue}\n${template}`;
  };

  const applyPreset = (
    presetKey: string,
    tierKey?: string | null,
    industryKey?: string | null,
    phoneKey?: string | null,
  ) => {
    const preset = requestPresets.find((item) => item.key === presetKey);
    if (!preset) {
      return;
    }

    const normalizedTier = tierKey ? formatTierLabel(tierKey) : null;
    const normalizedIndustry = industryKey?.trim() || null;
    let subject = normalizedTier ? `${preset.subject} - ${normalizedTier}` : preset.subject;
    if (normalizedIndustry) {
      subject = `${subject} (${normalizedIndustry})`;
    }

    let message = preset.message;
    message = fillTemplateLine(message, "Industry", normalizedIndustry);
    message = fillTemplateLine(message, "Mobile Phone", phoneKey);
    message = fillTemplateLine(message, "Requested tier", normalizedTier);

    setFormState((current) => ({
      ...current,
      subject,
      phone: current.phone || phoneKey || "",
      message: current.message.trim().length > 0 && current.message !== preset.message && current.message !== message ? current.message : message,
    }));
  };

  useEffect(() => {
    if (!intent) {
      return;
    }

    applyPreset(intent, tier, industry, phone);
  }, [intent, tier, industry, phone]);

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    setSending(true);
    setFormFeedback(null);

    try {
      const response = await fetch("/api/contact", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...formState,
          source,
          intent,
          requestedTier: tier,
          industry,
        }),
      });

      const data = await parseResponse(response);
      if (!response.ok) {
        throw new Error(data?.error || t("contact.error"));
      }

      setFormFeedback({
        type: "success",
        text: data?.delivery_status === "saved_only" ? t("contact.saved_only") : t("contact.success"),
      });
      setFormState({ name: "", email: "", phone: "", subject: "", message: "", smsConsent: false });
    } catch (error) {
      setFormFeedback({
        type: "error",
        text: error instanceof Error ? error.message : t("contact.error"),
      });
    } finally {
      setSending(false);
    }
  };

  const handleEarlyAccessSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    setEarlyAccessSending(true);
    setEarlyAccessFeedback(null);

    try {
      const response = await fetch("/api/contact/early-access", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          email: earlyAccessEmail,
          interest: earlyAccessInterest,
          source: "contact_page",
        }),
      });

      const data = await parseResponse(response);
      if (!response.ok) {
        throw new Error(data?.error || t("contact.error"));
      }

      let text: string = t("contact.early_access.success");
      if (data?.already_exists) {
        text = t("contact.early_access.updated");
      } else if (data?.delivery_status === "saved_only") {
        text = t("contact.early_access.saved_only");
      }

      setEarlyAccessFeedback({ type: "success", text });
      setEarlyAccessEmail("");
      setEarlyAccessInterest("");
    } catch (error) {
      setEarlyAccessFeedback({
        type: "error",
        text: error instanceof Error ? error.message : t("contact.error"),
      });
    } finally {
      setEarlyAccessSending(false);
    }
  };

  return (
    <div className="min-h-screen px-4 pb-12 pt-24 sm:px-6">
      <SEO
        title={t("contact.title")}
        description={t("seo.contact_description")}
        keywords="contact northern step studio, app support, partnership inquiries, customer service"
        canonicalUrl="/contact"
      />
      <div className="container mx-auto max-w-5xl">

        <div className="mb-12 text-center">
          <span className="mb-2 block text-xs text-accent text-label sm:text-sm">{t("contact.label")}</span>
          <h1 className="mb-4 text-3xl font-black uppercase tracking-tight sm:text-4xl lg:text-5xl leading-tight">
            <GlitchedText text={t("contact.title")} duration={600} />
          </h1>
          <p className="mx-auto max-w-2xl text-sm font-normal text-muted-foreground sm:text-base">
            {t("contact.subtitle")}
          </p>
        </div>

        <div className="mb-6 rounded-3xl border border-yellow-500/30 bg-gradient-to-r from-yellow-500/10 via-transparent to-transparent p-6">
          <div className="flex flex-col gap-5 lg:flex-row lg:items-start lg:justify-between">
            <div className="max-w-2xl">
              <div className="mb-3 inline-flex items-center gap-2 rounded-full border border-yellow-500/30 bg-yellow-500/10 px-3 py-1 text-[11px] font-black uppercase tracking-wider text-yellow-400">
                <PhoneCall className="h-3.5 w-3.5" />
                Best use of this form
              </div>
              <h2 className="text-2xl font-black uppercase tracking-tight text-foreground">
                Share project goals, not a vague quote request.
              </h2>
              <p className="mt-3 text-sm leading-relaxed text-muted-foreground">
                If you need support, have a partnership idea, or want to discuss a custom build, use the form below. We respond to all inquiries within 24-48 business hours.
              </p>
            </div>
            <div className="flex flex-wrap gap-2">
              {requestPresets.map((preset) => (
                <button
                  key={preset.key}
                  type="button"
                  onClick={() => applyPreset(preset.key, tier, industry, phone)}
                  className="rounded-full border border-border bg-background/80 px-4 py-2 text-xs font-black uppercase tracking-wider text-muted-foreground transition-colors hover:border-accent/40 hover:text-accent"
                >
                  {preset.label}
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 gap-6 lg:grid-cols-3">
          <div className="lg:col-span-2">
            <div className="card-dark-wise">


              <form onSubmit={handleSubmit} className="space-y-4">
                <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
                  <div>
                    <label htmlFor="name" className="mb-2 block text-sm font-medium">{t("contact.form.name")}</label>
                    <input
                      id="name"
                      title={t("contact.form.name")}
                      placeholder={t("contact.form.name") || "Your Name"}
                      type="text"
                      required
                      value={formState.name}
                      onChange={(event) => setFormState({ ...formState, name: event.target.value })}
                      className="w-full rounded-2xl border border-border bg-background px-4 py-3 transition-all focus:outline-none focus:ring-2 focus:ring-accent/50"
