    }

    if (!isValidEmailAddress(email)) {
      return c.json({ error: "Enter a valid email address." }, 400);
    }

    if (smsConsent && !phone) {
      return c.json({ error: "Enter a valid mobile phone number before opting into SMS." }, 400);
