    const destinationEmail = resolveContactDestination(subject, message);
    const sql = getDb(c.env);
    const [inserted] = await sql<{ id: number }[]>`
      INSERT INTO contact_messages (
         name,
         email,
         phone,
         subject,
         message,
         destination_email,
         sms_consent,
         source,
         intent,
         requested_tier,
