export type RetrievalRoute = "support" | "docs" | "faq" | "products" | "general";

export type StudioAgentRole =
  | "supervisor"
  | "utility-expert"
  | "finance-expert"
  | "support-expert"
  | "studio-expert"
  | "verifier";

